// ─── Dialed — PWA ───
// PWA manifest, theme, install banner, pull-to-refresh, visibility change.
// Loads after router.js.

// ─── PWA MANIFEST (injected dynamically so we can embed icons as base64) ───
(function() {
  const manifest = {
    name: 'Dialed — Extraction Tracker',
    short_name: 'Dialed',
    description: 'Track every espresso extraction. Dial in every roast.',
    start_url: window.location.href,
    display: 'standalone',
    background_color: '#b85215',
    theme_color: '#b85215',
    orientation: 'portrait',
    icons: [
      { src: 'data:image/png;base64,', sizes: '180x180', type: 'image/png' },
      { src: 'data:image/png;base64,', sizes: '180x180', type: 'image/png', purpose: 'maskable' },
      { src: 'data:image/png;base64,', sizes: '512x512', type: 'image/png', purpose: 'maskable any' }
    ]
  };
  const blob = new Blob([JSON.stringify(manifest)], {type: 'application/manifest+json'});
  const url = URL.createObjectURL(blob);
  document.getElementById('pwa-manifest').href = url;
})();

// ─── THEME ───
function applyTheme(theme) {
  localStorage.setItem('ext_theme', theme);
  const root = document.documentElement;
  if (theme === 'dark') {
    root.setAttribute('data-theme', 'dark');
  } else if (theme === 'light') {
    root.setAttribute('data-theme', 'light');
  } else {
    root.removeAttribute('data-theme');
  }
  // Update meta theme-color
  const mc = document.querySelector('meta[name="theme-color"]');
  if (mc) mc.content = theme === 'dark' ? '#18150f' : '#b85215';
}

function initTheme() {
  const saved = localStorage.getItem('ext_theme') || 'auto';
  applyTheme(saved);
  const sel = document.getElementById('p-theme');
  if (sel) sel.value = saved;
}

// Add CSS for forced theme overrides
const themeStyle = document.createElement('style');
themeStyle.textContent = `
  [data-theme="dark"] { color-scheme: dark; }
  [data-theme="light"] { color-scheme: light; }
  [data-theme="dark"] body {
    --bg: #18150f; --surface: #211d16; --surface2: #2a2520;
    --border: rgba(255,255,255,0.09); --border-strong: rgba(255,255,255,0.16);
    --text: #f0ece4; --muted: #9a9082; --hint: #5a544a;
    --accent: #d4672a; --accent-light: #2e1e0e;
    --info-bg: #0e1e3a; --info-text: #7aabf0; --info-border: rgba(122,171,240,0.25);
    --success-bg: #0a2018; --success-text: #5abf80; --success-border: rgba(90,191,128,0.25);
    --warning-bg: #281e06; --warning-text: #d4a030; --warning-border: rgba(212,160,48,0.25);
    --danger-text: #e07070; --danger-bg: #280f0f;
  }
  [data-theme="light"] body {
    --bg: #f8f5f0; --surface: #ffffff; --surface2: #f0ece4;
    --border: rgba(0,0,0,0.09); --border-strong: rgba(0,0,0,0.16);
    --text: #1c1814; --muted: #78726a; --hint: #b0a898;
    --accent: #b85215; --accent-light: #fdf0e8;
  }
  @media (prefers-color-scheme: dark) {
    #header-wordmark, .header-title img, .drawer-logo img, .auth-logo img { filter: invert(1) brightness(1.8); }
  }
  [data-theme="dark"] #header-wordmark,
  [data-theme="dark"] .header-title img,
  [data-theme="dark"] .drawer-logo img,
  [data-theme="dark"] .auth-logo img { filter: invert(1) brightness(1.8); }
  [data-theme="light"] #header-wordmark,
  [data-theme="light"] .header-title img,
  [data-theme="light"] .drawer-logo img,
  [data-theme="light"] .auth-logo img { filter: none; }
`;
document.head.appendChild(themeStyle);
initTheme();

// ─── PWA INSTALL ───
window.addEventListener('beforeinstallprompt', e => {
  e.preventDefault();
  deferredInstallPrompt = e;
  // Show banner after 30s if not dismissed
  const dismissed = localStorage.getItem('pwa_dismissed');
  if (!dismissed && !window.matchMedia('(display-mode: standalone)').matches) {
    setTimeout(showPWABanner, 30000);
  }
});

function showPWABanner() {
  const banner = document.getElementById('pwa-banner');
  if (banner) banner.classList.add('show');
}

function dismissPWA() {
  const banner = document.getElementById('pwa-banner');
  if (banner) banner.classList.remove('show');
  localStorage.setItem('pwa_dismissed', '1');
}

async function installPWA() {
  if (!deferredInstallPrompt) {
    // iOS fallback — show instructions
    alert('To install on iPhone:\n1. Tap the Share button (box with arrow)\n2. Scroll down and tap "Add to Home Screen"\n3. Tap "Add"');
    dismissPWA();
    return;
  }
  deferredInstallPrompt.prompt();
  const result = await deferredInstallPrompt.userChoice;
  deferredInstallPrompt = null;
  dismissPWA();
}

// ─── PULL TO REFRESH ───
// ─── VISIBILITY CHANGE (return from background / screen unlock) ───
document.addEventListener('visibilitychange', async () => {
  if (document.visibilityState === 'visible' && currentUser) {
    // App just came back from background — revalidate session silently
    // Only do this if we were showing the main app (not loading/auth screens)
    const mainApp = document.getElementById('main-app');
    if (mainApp && mainApp.style.display !== 'none') {
      const ok = await revalidateAndLoad();
      if (ok) {
        // Re-render current page with fresh data
        if (currentPage === 'home') renderHome();
        else if (currentPage === 'library') renderLibrary();
        else if (currentPage === 'insights') renderInsights();
        else if (currentPage === 'myshots') renderMyShots();
      }
    }
  }
});

(function() {
  let startY = 0, pulling = false, refreshed = false;
  const threshold = 80;

  document.addEventListener('touchstart', e => {
    if (window.scrollY === 0 && ['home','library'].includes(currentPage)) {
      startY = e.touches[0].clientY;
      pulling = true;
      refreshed = false;
    }
  }, {passive: true});

  document.addEventListener('touchmove', e => {
    if (!pulling) return;
    const dy = e.touches[0].clientY - startY;
    if (dy > 20 && dy < threshold + 40) {
      const ind = document.getElementById('ptr-indicator');
      if (ind) ind.classList.add('visible');
    }
  }, {passive: true});

  document.addEventListener('touchend', async e => {
    if (!pulling) return;
    pulling = false;
    const dy = e.changedTouches[0].clientY - startY;
    const ind = document.getElementById('ptr-indicator');
    if (dy > threshold && !refreshed) {
      refreshed = true;
      if (ind) ind.querySelector('span').textContent = 'Refreshing…';
      const ok = await revalidateAndLoad();
      if (ok) {
        if (currentPage === 'home') renderHome();
        if (currentPage === 'library') renderLibrary();
      }
    }
    if (ind) ind.classList.remove('visible');
  });
})();



// ─── SERVICE WORKER REGISTRATION ───
if ('serviceWorker' in navigator) {
  window.addEventListener('load', () => {
    navigator.serviceWorker.register('./sw.js')
      .then(reg => {
        reg.addEventListener('updatefound', () => {
          const newWorker = reg.installing;
          newWorker.addEventListener('statechange', () => {
            if (newWorker.state === 'installed' && navigator.serviceWorker.controller) {
              showUpdateBanner();
            }
          });
        });
      })
      .catch(err => console.log('SW registration failed:', err));

    let refreshing = false;
    navigator.serviceWorker.addEventListener('controllerchange', () => {
      if (!refreshing) { refreshing = true; window.location.reload(); }
    });
  });
}

function showUpdateBanner() {
  const banner = document.createElement('div');
  banner.id = 'update-banner';
  banner.style.cssText = 'position:fixed;bottom:80px;left:50%;transform:translateX(-50%);background:var(--surface);border:1px solid var(--border);border-radius:99px;padding:10px 18px;font-size:13px;font-weight:500;color:var(--text);z-index:35;box-shadow:var(--shadow);display:flex;align-items:center;gap:10px;white-space:nowrap;';
  banner.innerHTML = '<span>Update available</span><button onclick="applyUpdate()" style="background:var(--accent);color:#fff;border:none;border-radius:99px;padding:5px 12px;font-size:12px;font-weight:600;cursor:pointer;font-family:var(--font);">Refresh</button>';
  document.body.appendChild(banner);
}

function applyUpdate() {
  navigator.serviceWorker.getRegistration().then(reg => {
    if (reg && reg.waiting) {
      reg.waiting.postMessage({ type: 'SKIP_WAITING' });
    }
  });
}
